import React, { useEffect, useState } from 'react';
import CardProduto from '../CardProduto';
import Column from '../Column';
import * as C from './style';

function Main({ pedidos, pageRender, produtos }) {

    console.log(pedidos);

    const [ pedidos1, setPedidos1 ] = useState([]);
    const [ pedidos2, setPedidos2 ] = useState([]);
    const [ pedidos3, setPedidos3 ] = useState([]);
    const [ pedidos4, setPedidos4 ] = useState([]);
    const [ pedidos5, setPedidos5 ] = useState([]);

    let arrPedidos

    useEffect(() => {
        arrPedidos = pedidos.filter(e => e.horaEntrega == "19:30")
        setPedidos1(arrPedidos)
    }, [arrPedidos])


        
    if(pageRender === "Pedidos" && pedidos.length > 0){
        return (
            <C.ContainerPedidos>
                <Column title='19:30' pedidos={pedidos.filter(e => e.horaEntrega == "19:30")}/>
                <Column title='20:00' pedidos={pedidos.filter(e => e.horaEntrega == "20:00")}/>
                <Column title='20:30' pedidos={pedidos.filter(e => e.horaEntrega == "20:30")}/>
                <Column title='21:00' pedidos={pedidos.filter(e => e.horaEntrega == "21:00")}/>
                <Column title='21:30' pedidos={pedidos.filter(e => e.horaEntrega == "21:30")}/>
            </C.ContainerPedidos>
        )
    }

/*     if(pageRender === "Produtos"){
        console.log(produtos);
        return (
            <C.ContainerProdutos>
                {produtos.map( produto => (
                    <CardProduto key={produto.id} produto={produto}/>
                ))}
            </C.ContainerProdutos>
        )
    } */

    if(pageRender === "Pagamentos"){
        return (<div>Pagamentos</div>)
    }

    if(pageRender === "Controle Interno"){
        return (<div>Controle Interno</div>)
    }
    
}

export default Main
